import { IMessageComposer } from '@nitrots/nitro-renderer';

export class HaircutSelectStyleComposer implements IMessageComposer<any[]>
{
private _data: any[];

constructor(offerId: number, hrCode: string)
{
const id = Math.max(0, Math.floor(offerId || 0));

let sanitizedHr = '';

if(typeof hrCode === 'string' && hrCode.startsWith('hr-'))
{
// Allow only digits and dashes after hr-
const safe = hrCode.replace(/[^0-9\-]/g, '');
sanitizedHr = 'hr-' + safe.replace(/^hr-/, '');
}

this._data = [ id, sanitizedHr ];

console.log('[📤] HaircutSelectStyleComposer packet sent:', this._data);
}

public getMessageArray(): any[]
{
return this._data;
}

public dispose(): void
{
return;
}
}